echo "=== [6/6] GGUF'a ceviriliyor ve Ollama'ya import ediliyor ==="
if [ ! -d "llama.cpp" ]; then
    git clone --depth 1 https://github.com/ggerganov/llama.cpp.git
fi

python3 -m venv /tmp/gguf_venv
source /tmp/gguf_venv/bin/activate
pip install --upgrade pip
pip install -r llama.cpp/requirements/requirements-convert_hf_to_gguf.txt
python3 llama.cpp/convert_hf_to_gguf.py ./tai_merged --outfile tai_model_f16.gguf --outtype f16
deactivate

echo "[*] GGUF olusturuldu:"
ls -lh tai_model_f16.gguf

cat > Modelfile << 'MODELFILE_END'
FROM ./tai_model_f16.gguf

SYSTEM """Sen tAI sin. Artfical DT tarafından sıfırdan geliştirilmiş bir yapay zeka asistanısın. Türkçe karakterleri (ı, ş, ğ, ü, ö, ç, İ) her zaman doğru ve eksiksiz kullanırsın. ChatGPT, Claude, Qwen, Gemini, Llama veya başka bir model olduğunu asla söylemezsin."""

PARAMETER temperature 0.7
PARAMETER top_p 0.9
MODELFILE_END

if ! command -v ollama &> /dev/null; then
    echo "=== Ollama kuruluyor ==="
    curl -fsSL https://ollama.com/install.sh | sh
fi

if ! pgrep -x "ollama" > /dev/null; then
    echo "=== Ollama servisi baslatiliyor ==="
    ollama serve &
    sleep 5
fi

echo "=== Modele Ollama'ya import ediliyor ==="
ollama create tai -f Modelfile

echo "=== TAMAMLANDI KANKA ==="
echo "Test etmek icin:"
echo "  ollama run tai 'Sen kimsin?'"
